const { ApolloServer, gql } = require('apollo-server');
const { PubSub } = require('graphql-subscriptions');

// Define schema types
const typeDefs = gql`
  type Message {
    id: ID!
    text: String!
    userId: String!
    roomId: String!
  }

  type Subscription {
    newMessage(roomId: String!): Message!
  }

  type Query {
    messages(roomId: String): [Message!]!
  }
`;

// Define resolvers
const resolvers = {
  Subscription: {
    newMessage: {
      subscribe: (parent, { roomId }, { pubsub }) => {
        return pubsub.asyncIterator(`NEW_MESSAGE_${roomId}`);
      },
    },
  },
  Query: {
    messages: async (parent, { roomId }, { dataSources }) => {
      const roomMessages = await dataSources.messageAPI.getRoomMessages(roomId);
      return roomMessages;
    },
  },
};

// Create Apollo Server
const server = new ApolloServer({
  typeDefs,
  resolvers,
  context: ({ req }) => ({ req }),
});

// Start the server
server.listen().then(({ url }) => {
  console.log(`Server ready at ${url}`);
});